#[allow(unused_imports)]
use std::cmp::{min,max};
use std::collections::{*};
use std::io::{BufWriter, stdin, stdout, Write};
const BITS: usize = 19;

#[derive(Default)]
struct Scanner {
    buffer: Vec<String>
}
impl Scanner {
    fn next<T: std::str::FromStr>(&mut self) -> T {
        loop {
            if let Some(token) = self.buffer.pop() {
                return token.parse().ok().expect("Failed parse");
            }
            let mut input = String::new();
            stdin().read_line(&mut input).expect("Failed read");
            self.buffer = input.split_whitespace().rev().map(String::from).collect();
        }
    }
}

fn main() {
    let mut scanner = Scanner::default();
    let dx: [i32;3] = [1, 0, -1];
    let mut arr: [[u64;3];3] = [[0;3];3];
    for i in 0..3 {
    	for j in 0..3{
    		let times: u64 = scanner.next();
    		for x in &dx {
    			for y in &dx {
    				if i + *x < 3 && j + *y < 3 && i + *x > -1 && j + *y > -1 && (*x).abs() + (*y).abs() <= 1{
    					arr[(i + *x) as usize][(j + *y) as usize] += times;
    				}  
    			}
    		}
    	}
    }
    for i in 0usize..3{
    	for j in 0usize..3{
    		if arr[i][j]%2 == 1 {
    			print!["0"];
    		} else {
    			print!["1"];
    		}
    	}
    	println![""];
    }
}
